let webhookData = $input.first().json.body || $input.first().json;

if (typeof webhookData === 'string') {
  webhookData = JSON.parse(webhookData);
}

const docUrl = webhookData.doc_url;
const title = webhookData.title || webhookData.doc_title || 'Untitled';

if (!docUrl) {
  throw new Error('No doc_url in webhook payload. Received: ' + JSON.stringify(webhookData));
}

const match = docUrl.match(/\/documents\/(\d+)/);
if (!match) {
  throw new Error('Could not parse document ID from doc_url: ' + docUrl);
}

return [{ json: { document_id: match[1], title: title, doc_url: docUrl } }];

const docNode = $('Fetch Document Details').first().json;
const tagsResponse = $input.first().json;
const allTags = tagsResponse.results || tagsResponse || [];

const documentId = docNode.id;
const title = docNode.title;
const tagIds = docNode.tags || [];

const tagNames = [];
for (const tagId of tagIds) {
  const tag = allTags.find(t => t.id === tagId);
  if (tag) tagNames.push(tag.name);
}

const systemTags = ['inbox', 'processed', 'pending', 'review', 'archive', 'intake'];
let familyId = 'unknown';
for (const tagName of tagNames) {
  if (!systemTags.includes(tagName.toLowerCase())) {
    familyId = tagName.toLowerCase();
    break;
  }
}

return [{ json: {
  document_id: String(documentId),
  title: title,
  family_id: familyId,
  tag_names: tagNames,
  download_url: 'http://paperless:8000/api/documents/' + documentId + '/download/'
}}];

// Extract task_id from Docling chunking response
const response = $input.first().json;
console.log('Docling chunking response keys:', Object.keys(response));

const taskId = response.task_id || response.id || response.taskId;

if (!taskId) {
  // Maybe it returned the result directly (sync mode)?
  // Chunking endpoint returns 'chunks' array directly
  if (response.chunks || response.document || response.documents) {
    // Direct result - skip polling
    console.log('Direct result received with', (response.chunks || []).length, 'chunks');
    return [{ json: { direct_result: true, result: response } }];
  }
  throw new Error('No task_id in Docling response: ' + JSON.stringify(Object.keys(response)));
}

console.log('Async task started:', taskId);
return [{ json: { task_id: taskId, poll_count: 0, direct_result: false } }];

const statusResponse = $input.first().json;
const prevData = $('Wait 5s').first().json;
const taskId = prevData.task_id;
const pollCount = (prevData.poll_count || 0) + 1;

console.log('Poll #' + pollCount + ' - Response:', JSON.stringify(statusResponse));

// Handle array response
const status_obj = Array.isArray(statusResponse) ? statusResponse[0] : statusResponse;
const status = (status_obj.task_status || status_obj.status || status_obj.state || 'unknown').toLowerCase();

console.log('Status:', status);

// Check if conversion is complete
if (status === 'success' || status === 'completed' || status === 'done' || status === 'finished') {
  return [{ json: { task_id: taskId, is_complete: true, poll_count: pollCount } }];
}

// Check for failure - get error details
if (status === 'failure' || status === 'failed' || status === 'error') {
  const errorMsg = status_obj.task_meta || status_obj.error || status_obj.message || 'Unknown error';
  throw new Error('Docling conversion FAILED: ' + JSON.stringify(errorMsg) + '. Full response: ' + JSON.stringify(status_obj));
}

// Still processing - check if we've exceeded max polls (60 = 5 minutes)
if (pollCount >= 60) {
  throw new Error('Docling conversion timed out after 5 minutes. Last status: ' + JSON.stringify(statusResponse));
}

// Not complete yet, continue polling
return [{ json: { task_id: taskId, is_complete: false, poll_count: pollCount } }];

// Process hierarchical chunking response from Docling
// Response has 'chunks' array with page_numbers field
let doclingResponse;
try {
  const directCheck = $('Direct Result?');
  if (directCheck && directCheck.first) {
    const directItem = directCheck.first();
    if (directItem && directItem.json) {
      const directData = directItem.json;
      if (directData.direct_result && directData.result) {
        doclingResponse = directData.result;
      }
    }
  }
} catch (e) {
  // Direct result not available, will use input
}
if (!doclingResponse) {
  doclingResponse = $input.first().json;
}

const extractNode = $('Extract Document Info').first().json;
const documentId = extractNode.document_id;
const familyId = extractNode.family_id;
const title = extractNode.title;

console.log('Docling response keys:', Object.keys(doclingResponse));

// Get chunks from hierarchical chunking response
const doclingChunks = doclingResponse.chunks || [];
console.log('Received', doclingChunks.length, 'chunks from Docling');

if (doclingChunks.length === 0) {
  throw new Error('No chunks received from Docling. Response: ' + JSON.stringify(Object.keys(doclingResponse)));
}

// Convert Docling chunks to our format
const chunks = [];
const MIN_CHUNK_SIZE = 50;

for (let i = 0; i < doclingChunks.length; i++) {
  const chunk = doclingChunks[i];
  const text = chunk.text || chunk.raw_text || '';

  // Skip very small chunks
  if (text.trim().length < MIN_CHUNK_SIZE) {
    console.log('Skipping small chunk', i, ':', text.length, 'chars');
    continue;
  }

  // Get page number from page_numbers array (use first page if spans multiple)
  const pageNumbers = chunk.page_numbers || [];
  const pageNum = pageNumbers.length > 0 ? pageNumbers[0] : 1;

  chunks.push({
    text: text.trim(),
    page_num: pageNum,
    document_id: documentId,
    family_id: familyId,
    document_title: title,
    chunk_index: chunks.length,
    // Include headings for context if available
    headings: chunk.headings || []
  });
}

// Ensure at least one chunk
if (chunks.length === 0 && doclingChunks.length > 0) {
  const firstChunk = doclingChunks[0];
  chunks.push({
    text: (firstChunk.text || firstChunk.raw_text || 'Empty document').trim(),
    page_num: (firstChunk.page_numbers || [])[0] || 1,
    document_id: documentId,
    family_id: familyId,
    document_title: title,
    chunk_index: 0,
    headings: firstChunk.headings || []
  });
}

console.log('Created', chunks.length, 'chunks with page numbers');

// Log page distribution
const pageStats = {};
chunks.forEach(c => { pageStats[c.page_num] = (pageStats[c.page_num] || 0) + 1; });
console.log('Page distribution:', JSON.stringify(pageStats));

return chunks.map(c => ({ json: c }));

// Simple hash function for BM25 sparse vector generation
function hashCode(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash; // Convert to 32-bit integer
  }
  return Math.abs(hash);
}

// Get chunk data from previous node
const chunkData = $('Process Docling Chunks').item.json;
const embedding = $json.embedding;

if (!embedding || !Array.isArray(embedding)) {
  throw new Error('Failed to get embedding from Ollama. Response: ' + JSON.stringify($json));
}

// Generate BM25-compatible sparse vector from the chunk text
const text = chunkData.text.toLowerCase();
const words = text.split(/\W+/).filter(w => w.length > 2);
const wordCounts = {};
words.forEach(w => { wordCounts[w] = (wordCounts[w] || 0) + 1; });

// Convert to sparse format: {indices: [], values: []}
const indices = [];
const values = [];
Object.entries(wordCounts).forEach(([word, count]) => {
  indices.push(hashCode(word) % 30000);  // Hash to fixed vocab size
  values.push(count);
});

// Create integer point ID: document_id * 10000 + chunk_index
const pointId = parseInt(chunkData.document_id) * 10000 + chunkData.chunk_index;

return { json: {
  point_id: pointId,
  dense_vector: embedding,
  sparse_vector: { indices: indices, values: values },
  payload: chunkData
}};

// Loop back to Wait node with updated poll count
const taskId = $json.task_id;
const pollCount = $json.poll_count;
return [{ json: { task_id: taskId, poll_count: pollCount } }];

// Direct result path - extract from response
const data = $input.first().json;
return [{ json: data.result }];
